import { LandParcel } from '../types';

const getApiUrl = () => {
    const { hostname, protocol } = window.location;
    const isLocal = 
        hostname === 'localhost' || 
        hostname === '127.0.0.1' || 
        hostname.startsWith('192.168.') || 
        hostname.startsWith('10.') || 
        hostname.startsWith('172.');

    if (isLocal) {
        return `${protocol}//${hostname}:3004`;
    }
    return 'https://apigeo.gisvn.space'; 
};

export const API_URL = getApiUrl();

export interface ParcelDTO {
    gid?: number; 
    sothua: string;
    sodoto: string;
    tenchu?: string;
    diachi?: string;
    loaidat?: string; 
    dientich?: number;
    geometry?: any; 
    file?: File | null; 
    [key: string]: any; 
}

export interface SpatialTable {
    table_name: string;
    display_name: string;
    description?: string;
}

const getAuthHeaders = () => {
    const headers: any = { 'Content-Type': 'application/json' };
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId || u.branch_id;
        } catch (e) {}
    }
    return headers;
};

const handleResponse = async (res: Response) => {
    const responseText = await res.text();
    let responseData: any = null;
    if (responseText) {
        try { responseData = JSON.parse(responseText); } catch (e) {}
    }
    if (!res.ok) {
        let message = `Lỗi API (${res.status})`;
        if (responseData && (responseData.error || responseData.message)) {
            message = responseData.error || responseData.message;
        }
        throw new Error(message);
    }
    return responseData || { status: 'ok' };
};

export const parcelApi = {
    getAll: async (layer: string, filters?: { sodoto?: string, sothua?: string, tenchu?: string, diachi?: string }) => {
        let queryString = `?t=${Date.now()}`;
        if (filters) {
            if (filters.sodoto) queryString += `&sodoto=${encodeURIComponent(filters.sodoto)}`;
            if (filters.sothua) queryString += `&sothua=${encodeURIComponent(filters.sothua)}`;
            if (filters.tenchu) queryString += `&tenchu=${encodeURIComponent(filters.tenchu)}`;
            if (filters.diachi) queryString += `&diachi=${encodeURIComponent(filters.diachi)}`;
        }
        const res = await fetch(`${API_URL}/api/data/${layer}${queryString}`, { headers: { ...getAuthHeaders() } });
        return await handleResponse(res);
    },

    getExtent: async (layer: string) => {
        const res = await fetch(`${API_URL}/api/data/${layer}/extent`, { headers: { ...getAuthHeaders() } });
        return await handleResponse(res);
    },

    create: async (layer: string, data: ParcelDTO) => {
        const res = await fetch(`${API_URL}/api/data/${layer}`, { method: 'POST', headers: { ...getAuthHeaders() }, body: JSON.stringify(data) });
        return await handleResponse(res);
    },

    bulkCreate: async (layer: string, items: ParcelDTO[]) => {
        const res = await fetch(`${API_URL}/api/data/${layer}/bulk`, { 
            method: 'POST', 
            headers: { ...getAuthHeaders() }, 
            body: JSON.stringify({ items }) 
        });
        return await handleResponse(res);
    },

    createWithUpload: async (layer: string, data: ParcelDTO) => {
        const formData = new FormData();
        Object.keys(data).forEach(key => {
            if (key === 'file' && data[key]) formData.append('file', data[key] as File);
            else if (data[key] !== undefined && data[key] !== null) formData.append(key, String(data[key]));
        });
        const headers = { ...getAuthHeaders() };
        delete headers['Content-Type'];
        const res = await fetch(`${API_URL}/api/data/${layer}/upload`, { method: 'POST', headers, body: formData });
        return await handleResponse(res);
    },

    update: async (layer: string, gid: number, data: ParcelDTO) => {
        const res = await fetch(`${API_URL}/api/data/${layer}/${gid}`, { method: 'PUT', headers: { ...getAuthHeaders() }, body: JSON.stringify(data) });
        return await handleResponse(res);
    },

    updateGeometry: async (layer: string, gid: number, geometry: any, area: number) => {
        const res = await fetch(`${API_URL}/api/data/${layer}/${gid}/geometry`, { method: 'PUT', headers: { ...getAuthHeaders() }, body: JSON.stringify({ geometry, area }) });
        return await handleResponse(res);
    },

    delete: async (layer: string, gid: number) => {
        const res = await fetch(`${API_URL}/api/data/${layer}/${gid}`, { method: 'DELETE', headers: { ...getAuthHeaders() } });
        return await handleResponse(res);
    },

    manageTables: {
        getAll: async (): Promise<SpatialTable[]> => {
            const res = await fetch(`${API_URL}/api/spatial-tables?t=${Date.now()}`, { headers: { ...getAuthHeaders() } });
            return await handleResponse(res);
        },
        create: async (tableName: string, displayName?: string, description?: string) => {
            const name = (tableName || '').toLowerCase().trim();
            const res = await fetch(`${API_URL}/api/spatial-tables`, {
                method: 'POST',
                headers: { ...getAuthHeaders() },
                body: JSON.stringify({ tableName: name, displayName, description })
            });
            return await handleResponse(res);
        },
        link: async (tableName: string, displayName?: string, description?: string) => {
            const name = (tableName || '').toLowerCase().trim();
            const res = await fetch(`${API_URL}/api/spatial-tables/link`, {
                method: 'POST',
                headers: { ...getAuthHeaders() },
                body: JSON.stringify({ tableName: name, displayName, description })
            });
            return await handleResponse(res);
        },
        rename: async (oldName: string, newName: string, displayName: string, description?: string, renamePhysical?: boolean) => {
            const res = await fetch(`${API_URL}/api/spatial-tables/rename`, {
                method: 'POST',
                headers: { ...getAuthHeaders() },
                body: JSON.stringify({ 
                    oldName: oldName.toLowerCase().trim(), 
                    newName: newName.toLowerCase().trim(), 
                    displayName, 
                    description,
                    renamePhysical: !!renamePhysical
                })
            });
            return await handleResponse(res);
        },
        syncTable: async (tableName: string) => {
            const res = await fetch(`${API_URL}/api/spatial-tables/sync/${tableName}`, {
                method: 'POST',
                headers: { ...getAuthHeaders() }
            });
            return await handleResponse(res);
        },
        unlink: async (tableName: string) => {
            const name = (tableName || '').toLowerCase().trim();
            const res = await fetch(`${API_URL}/api/spatial-tables/unlink`, { 
                method: 'POST', 
                headers: { ...getAuthHeaders() }, 
                body: JSON.stringify({ tableName: name }) 
            });
            return await handleResponse(res);
        },
        delete: async (tableName: string) => {
            const name = (tableName || '').toLowerCase().trim();
            const res = await fetch(`${API_URL}/api/spatial-tables/${name}`, { method: 'DELETE', headers: { ...getAuthHeaders() } });
            return await handleResponse(res);
        }
    }
};

import express from 'express';
import multer from 'multer';
import shp from 'shpjs';
import fs from 'fs';

const upload = multer({ dest: 'uploads/' });

// Bộ nhớ đệm cho cấu trúc bảng và SRID (Schema Cache)
const SCHEMA_CACHE = new Map();

export default function(pool, logSystemAction) {
    const router = express.Router();

    const COLUMN_VARIANTS = {
        sodoto: ['shbando', 'sh_ban_do', 'tobando', 'to_ban_do', 'map_sheet', 'shmap', 'sodoto', 'so_to'],
        sothua: ['shthua', 'sh_thua', 'thua_dat', 'parcel_no', 'shparcel', 'so_thu_tu_thua', 'sothua', 'so_thua'],
        loaidat: ['kyhieumucd', 'ky_hieu_muc_dich', 'mucdich', 'mdsd', 'kh_mucdich', 'purpose', 'loaidat', 'loai_dat'],
        tenchu: ['tenchu', 'ten_chu', 'chu_so_huu', 'ten_chu_sd', 'owner', 'owner_name', 'chusudung'],
        diachi: ['diachi', 'dia_chi', 'vitri', 'vi_tri', 'address', 'location', 'khu_vuc'],
        dientich: ['dientich', 'dien_tich', 'dt_phaply', 'area', 'shape_area', 'st_area']
    };

    /**
     * Hàm tìm tên cột và SRID hiện tại của bảng
     */
    const resolveTableColumns = async (tableName) => {
        if (SCHEMA_CACHE.has(tableName)) {
            return SCHEMA_CACHE.get(tableName);
        }

        try {
            // Lấy danh sách cột
            const res = await pool.query(`
                SELECT column_name 
                FROM information_schema.columns 
                WHERE table_name = $1
            `, [tableName]);

            // Lấy SRID hiện tại của cột geometry
            const sridRes = await pool.query(`
                SELECT srid FROM geometry_columns 
                WHERE f_table_name = $1 AND f_geometry_column = 'geometry'
                LIMIT 1
            `, [tableName]);

            const currentSrid = sridRes.rows[0]?.srid || 4326;

            const dbColsMap = {};
            res.rows.forEach(r => {
                dbColsMap[r.column_name.toLowerCase()] = r.column_name;
            });

            const mapping = { _srid: currentSrid };
            for (const [standardKey, candidates] of Object.entries(COLUMN_VARIANTS)) {
                let foundCol = standardKey;
                for (const candidate of candidates) {
                    if (dbColsMap[candidate]) {
                        foundCol = dbColsMap[candidate];
                        break;
                    }
                }
                mapping[standardKey] = foundCol;
            }

            SCHEMA_CACHE.set(tableName, mapping);
            return mapping;
        } catch (e) {
            console.error(`Error resolving columns for ${tableName}:`, e);
            return { sodoto: 'sodoto', sothua: 'sothua', loaidat: 'loaidat', tenchu: 'tenchu', diachi: 'diachi', dientich: 'dientich', _srid: 4326 };
        }
    };

    const syncTableSchema = async (tableName) => {
        try {
            SCHEMA_CACHE.delete(tableName);
            const currentMap = await resolveTableColumns(tableName);
            const res = await pool.query(`SELECT column_name FROM information_schema.columns WHERE table_name = $1`, [tableName]);
            if (res.rows.length === 0) return; // Bảng không tồn tại vật lý

            const existingCols = res.rows.map(r => r.column_name.toLowerCase());

            // 1. Kiểm tra thiếu cột thuộc tính
            const missingCols = [];
            if (!existingCols.includes(currentMap.sodoto.toLowerCase())) missingCols.push({ name: 'sodoto', type: 'TEXT' });
            if (!existingCols.includes(currentMap.sothua.toLowerCase())) missingCols.push({ name: 'sothua', type: 'TEXT' });
            if (!existingCols.includes(currentMap.loaidat.toLowerCase())) missingCols.push({ name: 'loaidat', type: 'TEXT' });
            if (!existingCols.includes(currentMap.dientich.toLowerCase())) missingCols.push({ name: 'dientich', type: 'NUMERIC' });

            if (missingCols.length > 0) {
                for (const col of missingCols) {
                    await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "${col.name}" ${col.type}`);
                }
            }

            // 2. Tự động sửa SRID 4326 -> 9210 nếu cần
            if (currentMap._srid !== 9210) {
                try {
                    await pool.query(`
                        ALTER TABLE "${tableName}" 
                        ALTER COLUMN geometry TYPE geometry(Geometry, 9210) 
                        USING ST_SetSRID(geometry, 9210)
                    `);
                    console.log(`[Migrate] Forced SRID 9210 for table: ${tableName}`);
                } catch (err) {
                    console.warn(`[Migrate Skip] Could not force SRID 9210 for ${tableName}`);
                }
            }

            await pool.query(`CREATE INDEX IF NOT EXISTS "${tableName}_geom_idx" ON "${tableName}" USING GIST (geometry)`);
            SCHEMA_CACHE.delete(tableName); 
        } catch (e) {
            console.error(`[Schema Sync] Error syncing table ${tableName}:`, e.message);
        }
    };

    router.get('/spatial-tables', async (req, res) => {
        try {
            const result = await pool.query(`SELECT * FROM spatial_tables_registry ORDER BY created_at DESC`);
            res.json(result.rows);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/sync/:table', async (req, res) => {
        const { table } = req.params;
        try {
            await syncTableSchema(table);
            await logSystemAction(req, 'SYNC_TABLE', `Đồng bộ cấu trúc bảng: ${table}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        const safeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '_');
        try {
            await pool.query('BEGIN');
            await pool.query(`
                CREATE TABLE IF NOT EXISTS "${safeName}" (
                    gid SERIAL PRIMARY KEY,
                    sodoto TEXT, sothua TEXT, tenchu TEXT, diachi TEXT, loaidat TEXT, dientich NUMERIC,
                    geometry GEOMETRY(Geometry, 9210),
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            `);
            await pool.query(`CREATE INDEX IF NOT EXISTS "${safeName}_geom_idx" ON "${safeName}" USING GIST (geometry)`);
            await pool.query(`
                INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3)
                ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name
            `, [safeName, displayName, description]);

            await syncTableSchema(safeName);
            await pool.query('COMMIT');
            res.json({ status: 'ok', tableName: safeName });
        } catch (e) { await pool.query('ROLLBACK'); res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/link', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        try {
            const check = await pool.query(`SELECT to_regclass($1) as exists`, [tableName]);
            if (!check.rows[0].exists) throw new Error(`Bảng ${tableName} không tồn tại vật lý trong Database.`);
            await pool.query(`
                INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3)
                ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name, description = EXCLUDED.description
            `, [tableName, displayName, description]);

            await syncTableSchema(tableName);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/rename', async (req, res) => {
        const { oldName, newName, displayName, description, renamePhysical } = req.body;
        try {
            await pool.query('BEGIN');

            // Nếu người dùng yêu cầu đổi tên vật lý VÀ tên có thay đổi
            if (renamePhysical && oldName !== newName) {
                const check = await pool.query(`SELECT to_regclass($1) as exists`, [oldName]);
                if (check.rows[0].exists) {
                    await pool.query(`ALTER TABLE "${oldName}" RENAME TO "${newName}"`);
                }
            }

            // Luôn cập nhật Registry
            await pool.query(`
                UPDATE spatial_tables_registry 
                SET table_name = $1, display_name = $2, description = $3 
                WHERE table_name = $4
            `, [newName, displayName, description, oldName]);

            await pool.query('COMMIT');
            SCHEMA_CACHE.delete(oldName);
            SCHEMA_CACHE.delete(newName);
            res.json({ status: 'ok' });
        } catch (e) {
            await pool.query('ROLLBACK');
            res.status(500).json({ error: e.message });
        }
    });

    router.post('/spatial-tables/unlink', async (req, res) => {
        const { tableName } = req.body;
        try {
            await pool.query(`DELETE FROM spatial_tables_registry WHERE table_name = $1`, [tableName]);
            SCHEMA_CACHE.delete(tableName);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.get('/data/:table', async (req, res) => {
        const { table } = req.params;
        const { sodoto, sothua, tenchu, diachi } = req.query;
        try {
            const cols = await resolveTableColumns(table);
            let query = `
                SELECT gid, 
                "${cols.sodoto}" as sodoto, 
                "${cols.sothua}" as sothua, 
                "${cols.tenchu}" as tenchu, 
                "${cols.diachi}" as diachi, 
                "${cols.loaidat}" as loaidat, 
                "${cols.dientich}" as dientich, 
                ST_AsGeoJSON(geometry) as geometry 
                FROM "${table}" WHERE 1=1
            `;
            const params = [];
            let idx = 1;

            if (sodoto) { query += ` AND "${cols.sodoto}"::text = $${idx++}`; params.push(sodoto); }
            if (sothua) { query += ` AND "${cols.sothua}"::text = $${idx++}`; params.push(sothua); }
            if (tenchu) { query += ` AND "${cols.tenchu}" ILIKE $${idx++}`; params.push(`%${tenchu}%`); }
            if (diachi) { query += ` AND "${cols.diachi}" ILIKE $${idx++}`; params.push(`%${diachi}%`); }

            query += ` ORDER BY gid DESC LIMIT 100`;

            const result = await pool.query(query, params);
            res.json(result.rows.map(row => ({
                ...row,
                geometry: row.geometry ? JSON.parse(row.geometry) : null
            })));
        } catch (e) {
            SCHEMA_CACHE.delete(table);
            res.status(500).json({ error: e.message });
        }
    });

    router.post('/data/:table', async (req, res) => {
        const { table } = req.params;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            const targetSrid = cols._srid || 4326;

            let geomSql = 'NULL';
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            if (geometry) {
                geomSql = `ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($7), ${targetSrid}))`;
                params.push(JSON.stringify(geometry));
            }
            const query = `INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ${geomSql}) RETURNING gid`;
            const result = await pool.query(query, params);
            res.json({ status: 'ok', gid: result.rows[0].gid });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/data/:table/bulk', async (req, res) => {
        const { table } = req.params;
        const { items } = req.body;
        if (!Array.isArray(items) || items.length === 0) return res.status(400).json({ error: "Dữ liệu không hợp lệ." });
        try {
            const cols = await resolveTableColumns(table);
            const targetSrid = cols._srid || 4326;
            await pool.query('BEGIN');
            for (const item of items) {
                let geomSql = 'NULL';
                const params = [item.sodoto, item.sothua, item.tenchu, item.diachi, item.loaidat, item.dientich];
                if (item.geometry) {
                    geomSql = `ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($7), ${targetSrid}))`;
                    params.push(JSON.stringify(item.geometry));
                }
                const query = `INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ${geomSql})`;
                await pool.query(query, params);
            }
            await pool.query('COMMIT');
            await logSystemAction(req, 'BULK_IMPORT', `Nạp hàng loạt ${items.length} thửa đất vào bảng ${table}`);
            res.json({ status: 'ok', count: items.length });
        } catch (e) { await pool.query('ROLLBACK'); res.status(500).json({ error: e.message }); }
    });

    router.put('/data/:table/:gid', async (req, res) => {
        const { table, gid } = req.params;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            const targetSrid = cols._srid || 4326;
            let query = `UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6`;
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            let idx = 7;
            if (geometry) {
                query += `, geometry=ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($${idx}), ${targetSrid}))`;
                params.push(JSON.stringify(geometry));
                idx++;
            }
            query += ` WHERE gid=$${idx}`;
            params.push(gid);
            await pool.query(query, params);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/data/:table/upload', upload.single('file'), async (req, res) => {
        const { table } = req.params;
        const file = req.file;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, gid } = req.body; 
        if (!file) return res.status(400).json({ error: 'No file uploaded' });
        try {
            const cols = await resolveTableColumns(table);
            const targetSrid = cols._srid || 4326;
            const buffer = fs.readFileSync(file.path);
            let geojson;
            if (file.originalname.endsWith('.zip')) geojson = await shp(buffer);
            else geojson = JSON.parse(buffer.toString());
            let geometry = null;
            if (Array.isArray(geojson)) geometry = geojson[0]?.features[0]?.geometry;
            else if (geojson.type === 'FeatureCollection') geometry = geojson.features[0]?.geometry;
            else if (geojson.type === 'Feature') geometry = geojson.geometry;
            else geometry = geojson;
            if (!geometry) throw new Error("Không tìm thấy dữ liệu hình học.");
            if (gid) {
                await pool.query(`UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6, geometry=ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($7), ${targetSrid})) WHERE gid=$8`, [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry), gid]);
            } else {
                await pool.query(`INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($7), ${targetSrid})))`, [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry)]);
            }
            fs.unlinkSync(file.path);
            res.json({ status: 'ok' });
        } catch (e) {
            if (file && fs.existsSync(file.path)) fs.unlinkSync(file.path);
            res.status(500).json({ error: e.message });
        }
    });

    router.get('/data/:table/extent', async (req, res) => {
        try {
            const result = await pool.query(`SELECT ST_XMin(ext) as xmin, ST_YMin(ext) as ymin, ST_XMax(ext) as xmax, ST_YMax(ext) as ymax FROM (SELECT ST_Extent(geometry) as ext FROM "${req.params.table}") as t`);
            res.json(result.rows[0]);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/data/:table/:gid', async (req, res) => {
        try {
            await pool.query(`DELETE FROM "${req.params.table}" WHERE gid=$1`, [req.params.gid]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    return router;
}

import React, { useState, useEffect } from 'react';
import { adminService } from '../../services/mockBackend';
import { parcelApi } from '../../services/parcelApi';
import { WMSLayerConfig, BasemapConfig } from '../../types';
import { Layers, Database, Plus, Edit2, Trash2, X, Eye, EyeOff, Save, Table, Link2Off, RefreshCw, Map as MapIcon, CheckCircle2, Globe, AlertCircle, Check, ShieldAlert, Lock, Tags, Info, Sun, DatabaseZap, Search } from 'lucide-react';

interface LayerManagerProps {
    dbStatus: any;
}

const LayerManager: React.FC<LayerManagerProps> = ({ dbStatus }) => {
    const [wmsLayers, setWmsLayers] = useState<WMSLayerConfig[]>([]);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [modalType, setModalType] = useState<'LAYER' | 'TABLE' | 'BASEMAP' | null>(null);
    const [formData, setFormData] = useState<any>({});
    const [isEditMode, setIsEditMode] = useState(false);

    // Custom Confirmation Dialog State
    const [confirmDialog, setConfirmDialog] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        actionType: 'UNLINK' | 'DROP_TABLE' | 'DELETE_WMS' | 'DELETE_BASEMAP' | 'SYNC';
        targetId: string;
        targetName: string;
        isDangerous?: boolean;
    }>({
        isOpen: false,
        title: '',
        message: '',
        actionType: 'UNLINK',
        targetId: '',
        targetName: ''
    });

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        setLoading(true);
        setError(null);
        try {
            const [layers, tables, maps] = await Promise.all([
                adminService.getWmsLayers().catch(() => []),
                parcelApi.manageTables.getAll().catch(() => []),
                adminService.getBasemaps().catch(() => [])
            ]);
            setWmsLayers(layers || []);
            setSpatialTables(tables || []);
            setBasemaps(maps || []);
        } catch (e: any) {
            setError("Không thể tải toàn bộ dữ liệu cấu hình.");
        } finally { setLoading(false); }
    };

    const openModal = (type: 'LAYER' | 'TABLE' | 'BASEMAP', item?: any) => {
        setModalType(type);
        setIsEditMode(!!item);

        if (type === 'LAYER') {
            setFormData(item 
                ? { ...item, type: item.type || 'WMS', category: item.category || 'STANDARD', opacity: item.opacity ?? 1 } 
                : { name: '', url: '', layers: '', visible: true, opacity: 1, type: 'WMS', category: 'STANDARD' }
            );
        } else if (type === 'TABLE') {
            if (item) {
                setFormData({
                    tableName: item.table_name,
                    originalName: item.table_name, 
                    displayName: item.display_name || item.table_name,
                    description: item.description || '',
                    renamePhysical: false // Mặc định không đổi tên vật lý khi sửa Registry
                });
            } else {
                setFormData({
                    tableName: '',
                    displayName: '',
                    description: '',
                    isExisting: false
                });
            }
        } else if (type === 'BASEMAP') {
            setFormData(item ? { ...item } : { name: '', url: '', type: 'XYZ', isDefault: false, visible: true });
        }
        setIsModalOpen(true);
    };

    const handleSave = async () => {
        try {
            setLoading(true);
            let finalData = { ...formData };

            if (modalType === 'LAYER') {
                if (finalData.type === 'XYZ' && finalData.url) {
                    finalData.url = finalData.url.replace(/\${z}/g, '{z}').replace(/\${x}/g, '{x}').replace(/\${y}/g, '{y}');
                    if (!finalData.layers) finalData.layers = 'planning_tiles';
                }

                if (!finalData.name || !finalData.url) {
                    throw new Error("Vui lòng nhập Tên và URL cho lớp bản đồ.");
                }

                isEditMode ? await adminService.updateWmsLayer(finalData) : await adminService.addWmsLayer(finalData);
            } else if (modalType === 'BASEMAP') {
                isEditMode ? await adminService.updateBasemap(finalData) : await adminService.addBasemap(finalData);
            } else if (modalType === 'TABLE') {
                if (!finalData.tableName || !finalData.displayName) {
                    throw new Error("Vui lòng nhập đầy đủ Tên bảng vật lý và Tên hiển thị.");
                }
                if (isEditMode) {
                    await parcelApi.manageTables.rename(finalData.originalName, finalData.tableName, finalData.displayName, finalData.description, finalData.renamePhysical);
                } else {
                    if (finalData.isExisting) {
                        await parcelApi.manageTables.link(finalData.tableName, finalData.displayName, finalData.description);
                    } else {
                        await parcelApi.manageTables.create(finalData.tableName, finalData.displayName, finalData.description);
                    }
                }
            }
            setIsModalOpen(false);
            await loadData();
        } catch (e: any) { 
            setError(e.message);
        } finally { setLoading(false); }
    };

    const toggleWmsVisibility = async (layer: WMSLayerConfig) => {
        try {
            setLoading(true);
            await adminService.updateWmsLayer({ ...layer, visible: !layer.visible });
            await loadData();
        } catch (e: any) {
            setError(e.message);
        } finally { setLoading(false); }
    };

    const triggerConfirm = (type: typeof confirmDialog['actionType'], id: string, name: string) => {
        let title = '';
        let message = '';
        let isDangerous = false;

        switch(type) {
            case 'UNLINK':
                title = 'Hủy liên kết Registry';
                message = `Bạn có chắc chắn muốn hủy liên kết bảng "${name}"? Thao tác này chỉ xóa thông tin quản lý trong phần mềm, dữ liệu trong Database của bạn vẫn được giữ nguyên.`;
                break;
            case 'DROP_TABLE':
                title = 'XÓA VĨNH VIỄN BẢNG';
                message = `CẢNH BÁO NGUY HIỂM: Bạn đang yêu cầu xóa vĩnh viễn bảng "${name}" khỏi Database. Hành động này sẽ XÓA TOÀN BỘ DỮ LIỆU và không thể khôi phục.`;
                isDangerous = true;
                break;
            case 'DELETE_WMS':
                title = 'Xóa lớp chuyên đề';
                message = `Xóa cấu hình lớp bản đồ chuyên đề "${name}"?`;
                break;
            case 'DELETE_BASEMAP':
                title = 'Xóa bản đồ nền';
                message = `Xóa cấu hình bản đồ nền "${name}"?`;
                break;
            case 'SYNC':
                title = 'Đồng bộ cấu trúc';
                message = `Làm mới thông tin các cột (To, Thua, LoaiDat...) và SRID cho bảng "${name}" từ Database?`;
                break;
        }

        setConfirmDialog({
            isOpen: true,
            title,
            message,
            actionType: type,
            targetId: id,
            targetName: name,
            isDangerous
        });
    };

    const executeAction = async () => {
        const { actionType, targetId } = confirmDialog;
        setConfirmDialog(prev => ({ ...prev, isOpen: false }));
        setLoading(true);

        try {
            switch(actionType) {
                case 'UNLINK': await parcelApi.manageTables.unlink(targetId); break;
                case 'DROP_TABLE': await parcelApi.manageTables.delete(targetId); break;
                case 'DELETE_WMS': await adminService.deleteWmsLayer(targetId); break;
                case 'DELETE_BASEMAP': await adminService.deleteBasemap(targetId); break;
                case 'SYNC': await parcelApi.manageTables.syncTable(targetId); break;
            }
            await loadData();
        } catch (e: any) {
            setError("Lỗi thực thi: " + e.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="p-8 space-y-10 pb-24 max-w-7xl mx-auto font-sans">
            {error && (
                <div className="bg-red-900/20 border border-red-800 text-red-400 p-4 rounded-lg flex items-center justify-between gap-3 animate-in slide-in-from-top-2">
                    <div className="flex items-center gap-3">
                        <AlertCircle size={20} />
                        <span className="text-sm font-medium">{error}</span>
                    </div>
                    <button onClick={() => setError(null)} className="hover:text-white transition-colors"><X size={16}/></button>
                </div>
            )}

            {/* 1. DATABASE STATUS */}
            <div className="bg-gray-800 rounded-lg border border-gray-700 p-6 shadow-xl">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-lg font-bold flex items-center gap-2 text-white uppercase tracking-tighter">
                        <Database className="text-blue-400" /> Kết nối Database PostGIS
                    </h3>
                    <button onClick={loadData} disabled={loading} className="text-xs text-blue-400 hover:text-blue-300 flex items-center gap-1 transition-colors disabled:opacity-50 font-black uppercase tracking-widest">
                        <RefreshCw size={12} className={loading ? "animate-spin" : ""} /> Làm mới dữ liệu
                    </button>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm font-mono text-gray-300 bg-gray-900 p-4 rounded border border-gray-700 shadow-inner">
                    <p><span className="text-gray-500">Trạng thái:</span> <span className="text-green-400 font-bold">ĐANG KẾT NỐI</span></p>
                    <p><span className="text-gray-500">Database:</span> <span className="text-blue-400">{dbStatus.dbName || 'dulieu_geogis'}</span></p>
                </div>
            </div>

            {/* 2. SPATIAL TABLES REGISTRY */}
            <div className="bg-gray-800 rounded-lg border border-gray-700 shadow-xl overflow-hidden">
                <div className="p-4 flex justify-between border-b border-gray-700 bg-gray-800/50">
                    <span className="font-semibold text-gray-100 flex items-center gap-2">
                        <Table size={18} className="text-green-400"/> Quản lý Bảng Dữ liệu (Registry)
                    </span>
                    <button onClick={() => openModal('TABLE')} className="bg-green-600 hover:bg-green-500 text-white px-4 py-1.5 rounded text-sm font-bold flex items-center gap-1 transition-all">
                        <Plus size={16}/> Thêm / Liên kết
                    </button>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-900 text-gray-400 uppercase text-[10px] tracking-widest font-black">
                            <tr><th className="p-4 w-1/4">Tên bảng (DB)</th><th className="p-4 w-1/4">Tên hiển thị</th><th className="p-4 w-1/3">Mô tả</th><th className="p-4 text-right">Quản trị</th></tr>
                        </thead>
                        <tbody className="divide-y divide-gray-700 text-gray-300">
                            {spatialTables.map(t => (
                                <tr key={t.table_name} className="hover:bg-gray-700/30 transition-colors">
                                    <td className="p-4 font-mono text-blue-300 text-xs">{t.table_name}</td>
                                    <td className="p-4 font-medium text-white">{t.display_name || t.table_name}</td>
                                    <td className="p-4 text-xs text-gray-500 truncate max-w-[200px]">{t.description || '--'}</td>
                                    <td className="p-4 flex justify-end gap-1">
                                        <button onClick={() => triggerConfirm('SYNC', t.table_name, t.display_name || t.table_name)} className="p-2 text-emerald-400 hover:bg-emerald-400/10 rounded" title="Đồng bộ cấu trúc"><DatabaseZap size={16}/></button>
                                        <button onClick={() => openModal('TABLE', t)} className="p-2 text-blue-400 hover:bg-blue-400/10 rounded" title="Sửa thông số"><Edit2 size={16}/></button>
                                        <button onClick={() => triggerConfirm('UNLINK', t.table_name, t.display_name || t.table_name)} className="p-2 text-orange-400 hover:bg-orange-400/10 rounded" title="Hủy liên kết"><Link2Off size={16}/></button>
                                        <button onClick={() => triggerConfirm('DROP_TABLE', t.table_name, t.table_name)} className="p-2 text-red-500 hover:bg-red-500/10 rounded" title="Xóa vĩnh viễn"><Trash2 size={16}/></button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* 3. WMS LAYERS SECTION */}
            <div className="bg-gray-800 rounded-lg border border-gray-700 shadow-xl overflow-hidden">
                <div className="p-4 flex justify-between border-b border-gray-700 bg-gray-800/50">
                    <span className="font-semibold text-gray-100 flex items-center gap-2">
                        <Globe size={18} className="text-cyan-400"/> Lớp bản đồ & Quy hoạch (WMS/XYZ)
                    </span>
                    <button onClick={() => openModal('LAYER')} className="bg-cyan-600 hover:bg-cyan-500 text-white px-4 py-1.5 rounded text-sm font-bold flex items-center gap-1 transition-all shadow-lg shadow-cyan-950/20">
                        <Plus size={16}/> Thêm Lớp Dữ liệu
                    </button>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-900 text-gray-400 uppercase text-[10px] tracking-widest font-black">
                            <tr><th className="p-4">Tên hiển thị</th><th className="p-4">Loại</th><th className="p-4">Độ mờ</th><th className="p-4">Trạng thái</th><th className="p-4 text-right">Thao tác</th></tr>
                        </thead>
                        <tbody className="divide-y divide-gray-700 text-gray-300">
                            {wmsLayers.length === 0 ? (
                                <tr><td colSpan={5} className="p-10 text-center text-gray-600 italic">Chưa có lớp dữ liệu nào được cấu hình</td></tr>
                            ) : wmsLayers.map(l => (
                                <tr key={l.id} className="hover:bg-gray-700/30 transition-colors">
                                    <td className="p-4">
                                        <div className="flex flex-col">
                                            <span className="font-bold text-white">{l.name}</span>
                                            <span className={`text-[8px] font-black uppercase w-fit px-1.5 rounded mt-1 border ${l.category === 'PLANNING' ? 'bg-purple-900/40 text-purple-400 border-purple-800' : 'bg-gray-900 text-gray-500 border-gray-800'}`}>
                                                {l.category === 'PLANNING' ? 'Lớp Quy hoạch' : 'Lớp Chuyên đề'}
                                            </span>
                                        </div>
                                    </td>
                                    <td className="p-4">
                                        <span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase border ${l.type === 'XYZ' ? 'bg-orange-900/30 text-orange-400 border-orange-800/40' : 'bg-cyan-900/30 text-cyan-400 border-cyan-800/40'}`}>
                                            {l.type || 'WMS'}
                                        </span>
                                    </td>
                                    <td className="p-4">
                                        <div className="flex items-center gap-2">
                                            <Sun size={12} className="text-gray-500" />
                                            <span className="text-[11px] font-mono font-bold text-gray-400">{Math.round((l.opacity ?? 1) * 100)}%</span>
                                        </div>
                                    </td>
                                    <td className="p-4">
                                        <button onClick={() => toggleWmsVisibility(l)} className="flex items-center gap-2">
                                            {l.visible ? (
                                                <span className="flex items-center gap-1.5 text-green-400 text-[10px] uppercase font-black bg-green-900/20 px-2 py-1 rounded-full border border-green-800/40">
                                                    <Eye size={12}/> Đang hiện
                                                </span>
                                            ) : (
                                                <span className="flex items-center gap-1.5 text-gray-500 text-[10px] uppercase font-black bg-gray-900 px-2 py-1 rounded-full border border-gray-700">
                                                    <EyeOff size={12}/> Đang ẩn
                                                </span>
                                            )}
                                        </button>
                                    </td>
                                    <td className="p-4 flex justify-end gap-1">
                                        <button onClick={() => openModal('LAYER', l)} className="p-2 text-blue-400 hover:bg-blue-400/10 rounded transition-all"><Edit2 size={16}/></button>
                                        <button onClick={() => triggerConfirm('DELETE_WMS', l.id, l.name)} className="p-2 text-red-500 hover:bg-red-500/10 rounded transition-all"><Trash2 size={16}/></button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* 4. BASEMAPS SECTION */}
            <div className="bg-gray-800 rounded-lg border border-gray-700 shadow-xl overflow-hidden">
                <div className="p-4 flex justify-between border-b border-gray-700 bg-gray-800/50">
                    <span className="font-semibold text-gray-100 flex items-center gap-2">
                        <MapIcon size={18} className="text-orange-400"/> Quản lý Bản đồ nền (Basemaps)
                    </span>
                    <button onClick={() => openModal('BASEMAP')} className="bg-orange-600 hover:bg-orange-500 text-white px-4 py-1.5 rounded text-sm font-bold flex items-center gap-1 shadow-lg transition-all">
                        <Plus size={16}/> Thêm Bản đồ nền
                    </button>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-900 text-gray-400 uppercase text-[10px] tracking-widest font-black">
                            <tr><th className="p-4">Tên bản đồ</th><th className="p-4">Loại</th><th className="p-4">Mặc định</th><th className="p-4">Trạng thái</th><th className="p-4 text-right">Thao tác</th></tr>
                        </thead>
                        <tbody className="divide-y divide-gray-700 text-gray-300">
                            {basemaps.map(bm => (
                                <tr key={bm.id} className="hover:bg-gray-700/30 transition-colors">
                                    <td className="p-4 font-bold text-white">{bm.name}</td>
                                    <td className="p-4 text-xs font-mono text-gray-400">{bm.type}</td>
                                    <td className="p-4">
                                        {bm.isDefault ? (
                                            <span className="bg-orange-900/40 text-orange-400 text-[9px] px-2 py-0.5 rounded-full border border-orange-800 font-black uppercase">Mặc định</span>
                                        ) : '--'}
                                    </td>
                                    <td className="p-4">{bm.visible ? <span className="text-green-400 text-[10px] uppercase font-bold">Hiện</span> : <span className="text-gray-500 text-[10px] uppercase font-bold">Ẩn</span>}</td>
                                    <td className="p-4 flex justify-end gap-1">
                                        <button onClick={() => openModal('BASEMAP', bm)} className="p-2 text-blue-400 hover:bg-blue-400/10 rounded transition-all"><Edit2 size={16}/></button>
                                        <button onClick={() => triggerConfirm('DELETE_BASEMAP', bm.id, bm.name)} className="p-2 text-red-500 hover:bg-red-500/10 rounded transition-all"><Trash2 size={16}/></button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* --- CONFIRMATION MODAL & MAIN FORM MODAL --- */}
            {confirmDialog.isOpen && (
                <div className="fixed inset-0 z-[600] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-800 rounded-2xl w-full max-w-sm border border-gray-700 shadow-2xl overflow-hidden">
                        <div className={`p-6 flex flex-col items-center text-center ${confirmDialog.isDangerous ? 'bg-red-950/20' : 'bg-orange-950/20'}`}>
                            <div className={`w-16 h-16 rounded-full flex items-center justify-center mb-4 ${confirmDialog.isDangerous ? 'bg-red-500 text-white' : (confirmDialog.actionType === 'SYNC' ? 'bg-emerald-500 text-white' : 'bg-orange-500 text-white')}`}>
                                {confirmDialog.actionType === 'SYNC' ? <DatabaseZap size={32}/> : <ShieldAlert size={32} />}
                            </div>
                            <h3 className="text-xl font-black text-white uppercase tracking-tight mb-2">{confirmDialog.title}</h3>
                            <p className="text-gray-400 text-sm leading-relaxed">{confirmDialog.message}</p>
                        </div>
                        <div className="p-4 bg-gray-900/50 flex gap-3">
                            <button onClick={() => setConfirmDialog(prev => ({ ...prev, isOpen: false }))} className="flex-1 py-3 text-sm font-bold text-gray-400 hover:text-white uppercase">Hủy bỏ</button>
                            <button onClick={executeAction} className={`flex-1 py-3 text-sm font-black rounded-xl uppercase shadow-lg ${confirmDialog.isDangerous ? 'bg-red-600 hover:bg-red-500 text-white' : (confirmDialog.actionType === 'SYNC' ? 'bg-emerald-600 hover:bg-emerald-500 text-white' : 'bg-blue-600 hover:bg-blue-500 text-white')}`}>Xác nhận</button>
                        </div>
                    </div>
                </div>
            )}

            {isModalOpen && (
                <div className="fixed inset-0 z-[500] bg-black/85 backdrop-blur-sm flex items-center justify-center p-4 overflow-y-auto">
                    <div className="bg-gray-800 rounded-xl w-full max-w-md p-6 border border-gray-700 shadow-2xl animate-in zoom-in-95 duration-200 my-auto">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-700 pb-3">
                            <h3 className="text-xl font-bold text-white uppercase tracking-tighter flex items-center gap-2">
                                {modalType === 'TABLE' && <Table className="text-green-400"/>}
                                {modalType === 'LAYER' && <Globe className="text-cyan-400"/>}
                                {modalType === 'BASEMAP' && <MapIcon className="text-orange-400"/>}
                                {isEditMode ? "Chỉnh sửa" : "Thêm mới"}
                            </h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-500 hover:text-white transition-colors"><X size={24}/></button>
                        </div>

                        <div className="space-y-5">
                            {modalType === 'LAYER' && (
                                <>
                                    <div className="bg-gray-950 p-1 rounded flex gap-1 shadow-inner mb-4">
                                        <button onClick={() => setFormData({...formData, type: 'WMS'})} className={`flex-1 py-2 text-[10px] font-black rounded uppercase transition-all ${formData.type === 'WMS' ? 'bg-cyan-600 text-white shadow-md' : 'text-gray-500 hover:text-gray-300'}`}>Chuẩn WMS</button>
                                        <button onClick={() => setFormData({...formData, type: 'XYZ'})} className={`flex-1 py-2 text-[10px] font-black rounded uppercase transition-all ${formData.type === 'XYZ' ? 'bg-orange-600 text-white shadow-md' : 'text-gray-500 hover:text-gray-300'}`}>Chuẩn XYZ Tiles</button>
                                    </div>

                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase mb-3 block tracking-[0.15em]">Phân loại lớp bản đồ</label>
                                        <div className="grid grid-cols-2 gap-2 bg-gray-900 p-1 rounded-xl">
                                            <button onClick={() => setFormData({...formData, category: 'STANDARD'})} className={`py-2 text-[10px] font-black rounded-lg uppercase transition-all ${formData.category === 'STANDARD' ? 'bg-blue-600 text-white shadow-md' : 'text-gray-500 hover:text-gray-300'}`}>Chuyên đề</button>
                                            <button onClick={() => setFormData({...formData, category: 'PLANNING'})} className={`py-2 text-[10px] font-black rounded-lg uppercase transition-all ${formData.category === 'PLANNING' ? 'bg-purple-600 text-white shadow-md' : 'text-gray-500 hover:text-gray-300'}`}>Quy hoạch</button>
                                        </div>
                                    </div>

                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">Tên hiển thị (VD: Quy hoạch TDM)</label>
                                        <input className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white outline-none focus:border-cyan-500 font-bold" value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})}/>
                                    </div>

                                    {formData.type === 'WMS' && (
                                        <div className="space-y-3">
                                            <div>
                                                <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">Lớp (Workspace:Layer)</label>
