    searchParcels: async (tableName: string, filters: any): Promise<LandParcel[]> => {
        try {
             let qs = `?t=${Date.now()}`;
             if (filters.sodoto) qs += `&sodoto=${encodeURIComponent(filters.sodoto)}`;
             if (filters.sothua) qs += `&sothua=${encodeURIComponent(filters.sothua)}`;
