const uploadDir = path.resolve(__dirname, 'uploads');
if (!fs.existsSync(uploadDir)) fs.mkdirSync(uploadDir, { recursive: true });

const { Pool } = pg;
const pool = new Pool({ ...dbConfig, connectionTimeoutMillis: 10000 });
const port = 3004;

// Khởi tạo Express App
const app = express();

// --- CẤU HÌNH GIỚI HẠN TÊN MIỀN (CORS WHITELIST) ---
const allowedOrigins = [
  'https://geo.gisvn.space',
  'https://www.geo.gisvn.space',
  'https://qlddhcm.io.vn',       // Domain mới
  'https://www.qlddhcm.io.vn',   // Domain mới
  'http://localhost:3003', // Port Custom
  'http://127.0.0.1:3003',
  'http://localhost:3000', // Create React App Default
  'http://localhost:5173', // Vite Default
  'http://127.0.0.1:5173'
];

app.use(cors({
    origin: function (origin, callback) {
        // Cho phép các yêu cầu không có origin (như mobile apps hoặc curl)
        if (!origin) return callback(null, true);

        if (allowedOrigins.indexOf(origin) === -1) {
            // Log warning thay vì error để dễ debug
            console.warn(`[CORS Blocked] Origin: ${origin}`);
            // Trong dev mode, có thể tạm thời cho phép tất cả để tránh phiền phức
            // return callback(null, true); 

            const msg = 'Chính sách CORS của hệ thống không cho phép truy cập từ nguồn này.';
            return callback(new Error(msg), false);
        }
        return callback(null, true);
    },
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization', 'x-user-id', 'x-user-name', 'x-branch-id'],
    credentials: true
}));

app.use(express.json({ limit: '50mb' }));
app.enable('trust proxy');

